```
import type { Processor } from '@mastra/core/processors';
import { createTool } from '@mastra/core/tools';
import { MASTRA_THREAD_ID_KEY } from '@mastra/core/request-context';
import { z } from 'zod';
import { logMode } from '../lib/logger';

type AnyTool = any;

type ThreadState = {
  loadedToolIds: Set<string>;
  lastAccessed: number;
};

type MultiToolLoaderOptions = {
  tools: Record<string, AnyTool>;
};

export class MultiToolLoaderProcessor implements Processor {
  readonly id = 'multi-tool-loader';
  private readonly allTools: Record<string, AnyTool>;
  private readonly threadStates = new Map<string, ThreadState>();

  constructor(options: MultiToolLoaderOptions) {
    this.allTools = options.tools ?? {};
  }

  private getThreadId(requestContext: any): string {
    const fromCtx =
      requestContext?.get?.(MASTRA_THREAD_ID_KEY) ??
      requestContext?.get?.('thread_id') ??
      requestContext?.get?.('thread');
    const normalized = String(fromCtx ?? '').trim();
    return normalized || 'default';
  }

  private getThreadState(threadId: string): ThreadState {
    const existing = this.threadStates.get(threadId);
    if (existing) {
      existing.lastAccessed = Date.now();
      return existing;
    }
    const created: ThreadState = {
      loadedToolIds: new Set<string>(),
      lastAccessed: Date.now(),
    };
    this.threadStates.set(threadId, created);
    return created;
  }

  private resolveTool(toolNameOrId: string): { id: string; tool: AnyTool } | null {
    const normalized = String(toolNameOrId ?? '').trim();
    if (!normalized) return null;

    const direct = this.allTools[normalized];
    if (direct) {
      const id = String(direct?.id ?? normalized).trim() || normalized;
      return { id, tool: direct };
    }

    for (const candidate of Object.values(this.allTools)) {
      const id = String(candidate?.id ?? '').trim();
      if (id && id === normalized) {
        return { id, tool: candidate };
      }
    }

    return null;
  }

  private getLoadedTools(threadId: string): Record<string, AnyTool> {
    const state = this.getThreadState(threadId);
    const loaded: Record<string, AnyTool> = {};
    for (const toolId of state.loadedToolIds) {
      const resolved = this.resolveTool(toolId);
      if (!resolved) continue;
      loaded[resolved.id] = resolved.tool;
    }
    return loaded;
  }

  private buildLoadToolsTool(threadId: string) {
    return createTool({
      id: 'load_tools',
      description:
        'Load one or more known tools by name/id in a single call. Loaded tools are available on the next step.',
      inputSchema: z.object({
        toolNames: z.array(z.string().min(1)).min(1).describe('Exact tool names/ids to load'),
      }),
      outputSchema: z.object({
        results: z.array(
          z.object({
            toolName: z.string(),
            loadedToolId: z.string().optional(),
            success: z.boolean(),
            message: z.string(),
          })
        ),
      }),
      execute: async ({ toolNames }) => {
        const state = this.getThreadState(threadId);
        const results = toolNames.map((toolName) => {
          const resolved = this.resolveTool(toolName);
          if (!resolved) {
            return {
              toolName,
              success: false,
              message: `Tool "${toolName}" not found.`,
            };
          }

          if (state.loadedToolIds.has(resolved.id)) {
            return {
              toolName,
              loadedToolId: resolved.id,
              success: true,
              message: `Tool "${resolved.id}" already loaded.`,
            };
          }

          state.loadedToolIds.add(resolved.id);
          return {
            toolName,
            loadedToolId: resolved.id,
            success: true,
            message: `Tool "${resolved.id}" loaded.`,
          };
        });

        logMode('load_tools executed', 'pindown-chat-agent', {
          threadId,
          requestedCount: toolNames.length,
          successCount: results.filter((r) => r.success).length,
        });

        return { results };
      },
    });
  }

  async processInputStep({ requestContext, tools }: any): Promise<any> {
    const threadId = this.getThreadId(requestContext);
    const loadedTools = this.getLoadedTools(threadId);
    const loadTools = this.buildLoadToolsTool(threadId);

    return {
      tools: {
        ...(tools && typeof tools === 'object' ? tools : {}),
        ...loadedTools,
        load_tools: loadTools,
      },
    };
  }
}


```

