## Minimal Reproduction

Here's a standalone script demonstrating the issue:

```typescript
#!/usr/bin/env npx tsx
/**
 * Minimal reproduction: dountil iteration state not preserved for time-travel
 * Run: npx tsx repro.mts
 */

import { Mastra } from '@mastra/core';
import { createWorkflow, createStep } from '@mastra/core/workflows';
import { LibSQLStore } from '@mastra/libsql';
import { z } from 'zod';

// Simple counter step that runs in a dountil loop
const counterStep = createStep({
  id: 'counter',
  inputSchema: z.object({
    count: z.number(),
    maxCount: z.number(),
  }),
  outputSchema: z.object({
    count: z.number(),
    maxCount: z.number(),
    message: z.string(),
  }),
  stateSchema: z.object({
    iterations: z.array(z.object({
      iteration: z.number(),
      timestamp: z.string(),
    })).optional(),
  }),
  execute: async ({ inputData, state, setState }) => {
    const newCount = inputData.count + 1;

    // Manually accumulate iteration history in state (workaround)
    await setState({
      iterations: [...(state?.iterations || []), {
        iteration: newCount,
        timestamp: new Date().toISOString(),
      }],
    });

    console.log(`  Iteration ${newCount}/${inputData.maxCount}`);

    return {
      count: newCount,
      maxCount: inputData.maxCount,
      message: `Completed iteration ${newCount}`,
    };
  },
});

const counterWorkflow = createWorkflow({
  id: 'counter-workflow',
  inputSchema: z.object({ maxCount: z.number() }),
  outputSchema: z.object({ count: z.number(), maxCount: z.number(), message: z.string() }),
  stateSchema: z.object({
    iterations: z.array(z.object({ iteration: z.number(), timestamp: z.string() })).optional(),
  }),
})
  .map(({ inputData }) => ({ count: 0, maxCount: inputData.maxCount }))
  .dountil(counterStep, ({ inputData }) => inputData.count >= inputData.maxCount)
  .commit();

async function main() {
  const storage = new LibSQLStore({ id: 'repro', url: ':memory:' });
  await storage.init();

  const mastra = new Mastra({
    storage,
    workflows: { 'counter-workflow': counterWorkflow },
    logger: false,
  });

  counterWorkflow.__registerMastra(mastra);
  counterWorkflow.__registerPrimitives({
    logger: mastra.getLogger(),
    storage: mastra.getStorage(),
  });

  console.log('=== Running workflow with 4 iterations ===\n');
  const run = await counterWorkflow.createRun();
  await run.start({ inputData: { maxCount: 4 } });

  // Examine snapshot
  const store = await storage.getStore('workflows');
  const snapshot = await store?.loadWorkflowSnapshot({
    workflowName: 'counter-workflow',
    runId: run.runId,
  });

  console.log('\n=== snapshot.context.counter ===');
  console.log(JSON.stringify(snapshot?.context?.counter, null, 2));

  console.log('\n=== PROBLEM ===');
  console.log('Only iteration 4 is in context. Iterations 1-3 are gone.');
  console.log('metadata.iterationCount:', (snapshot?.context?.counter as any)?.metadata?.iterationCount);

  console.log('\n=== Workaround: manually accumulated in snapshot.value ===');
  console.log(JSON.stringify(snapshot?.value?.iterations, null, 2));

  // Time-travel requires manual reconstruction
  console.log('\n=== Time-travel to iteration 2 requires manual work ===');
  const iterations = (snapshot?.value as any)?.iterations || [];

  await run.timeTravel({
    step: 'counter',
    inputData: { count: 1, maxCount: 4 },  // Must manually calculate
    initialState: { iterations: iterations.slice(0, 1) },  // Must manually slice
  });

  console.log('\n=== DESIRED ===');
  console.log('await run.timeTravel({ step: "counter", iteration: 2 })');
}

main();
```

## Output

```
=== Running workflow with 4 iterations ===

  Iteration 1/4
  Iteration 2/4
  Iteration 3/4
  Iteration 4/4

=== snapshot.context.counter ===
{
  "payload": { "count": 3, "maxCount": 4 },
  "status": "success",
  "metadata": { "iterationCount": 4 },
  "output": { "count": 4, "maxCount": 4, "message": "Completed iteration 4" }
}

=== PROBLEM ===
Only iteration 4 is in context. Iterations 1-3 are gone.
metadata.iterationCount: 4

=== Workaround: manually accumulated in snapshot.value ===
[
  { "iteration": 1, "timestamp": "..." },
  { "iteration": 2, "timestamp": "..." },
  { "iteration": 3, "timestamp": "..." },
  { "iteration": 4, "timestamp": "..." }
]

=== Time-travel to iteration 2 requires manual work ===
  Iteration 2/4
  Iteration 3/4
