something like this
```
  useCopilotAction({
    name: "updateStoryLine",
    handler: async ({ args }) => {
      let streamedStoryLine = "";

      const response = await client.api.ai.mastra.$post({ promt: args.promt });

      const reader = response.body.getReader();
      const decoder = new TextDecoder();

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        const nextChunk = decoder.decode(value)

        streamedStoryLine += nextChunk;
        mergeState(currentStory, streamedStoryLine);
      }  
    },
  });
